1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, nextGenerationSparse, type Grid } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill single live cell (underpopulation)", () => {
9	    // Grid: 3x3, center cell (1,1) is alive, no neighbors
10	    const grid: Grid = [
11	      [false, false, false],
12	      [false, true, false],
13	      [false, false, false],
14	    ];
15	    const result = nextGeneration(grid);
16	    // Center cell should be dead - it has 0 neighbors (underpopulation)
17	    expect(result).toEqual([
18	      [false, false, false],
19	      [false, false, false],
20	      [false, false, false],
21	    ]);
22	  });
23	  it("should kill live cell with one neighbor (underpopulation)", () => {
24	    // Grid: 3x3, center cell (1,1) is alive, only cell (1,2) is alive
25	    const grid: Grid = [
26	      [false, false, false],
27	      [true, true, false],
28	      [false, false, false],
29	    ];
30	    const result = nextGeneration(grid);
31	    // Both cells should be dead - center has 1 neighbor (underpopulation)
32	    expect(result).toEqual([
33	      [false, false, false],
34	      [false, false, false],
35	      [false, false, false],
36	    ]);
37	  });
38	  it("should keep live cell alive with 2 neighbors (survival)", () => {
39	    // Grid: 3x3, center cell (1,1) is alive with 2 neighbors
40	    const grid: Grid = [
41	      [false, false, false],
42	      [true, true, true],
43	      [false, false, false],
44	    ];
45	    const result = nextGeneration(grid);
46	    // Center cell should stay alive (2 neighbors = survival)
47	    expect(result).toEqual([
48	      [false, true, false],
49	      [false, true, false],
50	      [false, true, false],
51	    ]);
52	  });
53	  it("should keep live cell with three neighbors (survival)", () => {
54	    // Grid: 3x3, center cell (1,1) is alive with 2 neighbors
55	    const grid: Grid = [
56	      [false, true, false],
57	      [true, true, false],
58	      [false, false, false],
59	    ];
60	    const result = nextGeneration(grid);
61	    // Center cell should stay alive (2 neighbors = survival)
62	    // (0,0) should be born (3 neighbors = reproduction)
63	    expect(result).toEqual([
64	      [true, true, false],
65	      [true, true, false],
66	      [false, false, false],
67	    ]);
68	  });
69	  it("should kill live cell with four neighbors (overpopulation)", () => {
70	    // Grid: 3x3, center cell (1,1) is alive with 3 neighbors
71	    const grid: Grid = [
72	      [true, false, true],
73	      [true, true, false],
74	      [false, false, false],
75	    ];
76	    const result = nextGeneration(grid);
77	    // Center cell should survive (3 neighbors = survival)
78	    // (0,2) should die (1 neighbor = underpopulation)
79	    expect(result).toEqual([
80	      [true, false, false],
81	      [true, true, false],
82	      [false, false, false],
83	    ]);
84	  });
85	  it("should revive dead cell with exactly 3 neighbors (reproduction)", () => {
86	    // Grid: 3x3, center cell (1,1) is dead with 3 neighbors
87	    const grid: Grid = [
88	      [false, true, false],
89	      [true, false, true],
90	      [false, false, false],
91	    ];
92	    const result = nextGeneration(grid);
93	    // Center cell should be alive (dead cell with 3 neighbors = reproduction)
94	    // (1,0) should die (1 neighbor = underpopulation)
95	    // (1,2) should die (1 neighbor = underpopulation)
96	    expect(result).toEqual([
97	      [false, true, false],
98	      [false, true, false],
99	      [false, false, false],
100	    ]);
101	  });
102	  it("should not revive dead cell with two neighbors", () => {
103	    // Grid: 3x3, center cell (1,1) is dead with 2 neighbors
104	    const grid: Grid = [
105	      [false, false, false],
106	      [true, false, true],
107	      [false, false, false],
108	    ];
109	    const result = nextGeneration(grid);
110	    // Center cell should stay dead (dead cell with 2 neighbors = no reproduction)
111	    expect(result).toEqual([
112	      [false, false, false],
113	      [false, false, false],
114	      [false, false, false],
115	    ]);
116	  });
117	  it("should not revive dead cell with four neighbors", () => {
118	    // Grid: 5x5, center cell (2,2) is dead with exactly 4 neighbors
119	    // Only the 4 corner neighbors of center are alive, all others dead
120	    const grid: Grid = [
121	      [false, false, false, false, false],
122	      [false, true, false, true, false],
123	      [false, false, false, false, false],
124	      [false, true, false, true, false],
125	      [false, false, false, false, false],
126	    ];
127	    const result = nextGeneration(grid);
128	    // Center cell (2,2) should stay dead (dead cell with 4 neighbors = no reproduction)
129	    // The 4 neighbors each have 2 neighbors (not 2 or 3 alive neighbors for survival)
130	    // so they should all die too
131	    expect(result).toEqual([
132	      [false, false, false, false, false],
133	      [false, false, false, false, false],
134	      [false, false, false, false, false],
135	      [false, false, false, false, false],
136	      [false, false, false, false, false],
137	    ]);
138	  });
139	  it("should apply rules to multiple cells simultaneously", () => {
140	    // Grid: 5x5 with multiple live cells that need different rule applications
141	    // Live cells at (1,1), (1,2), (3,2), (3,3)
142	    const grid: Grid = [
143	      [false, false, false, false, false],
144	      [false, true, true, false, false],
145	      [false, false, false, false, false],
146	      [false, false, true, true, false],
147	      [false, false, false, false, false],
148	    ];
149	    const result = nextGeneration(grid);
150	    // (1,1) has 1 neighbor -> dies
151	    // (1,2) has 1 neighbor -> dies
152	    // (3,2) has 1 neighbor -> dies
153	    // (3,3) has 1 neighbor -> dies
154	    // (2,1) has 3 neighbors -> born
155	    // (2,3) has 3 neighbors -> born
156	    expect(result).toEqual([
157	      [false, false, false, false, false],
158	      [false, false, false, false, false],
159	      [false, true, false, true, false],
160	      [false, false, false, false, false],
161	      [false, false, false, false, false],
162	    ]);
163	  });
164	  it("should work with negative coordinates", () => {
165	    // Test sparse grid representation with coordinate keys
166	    // This allows negative coordinates: Map<string, boolean>
167	    // Expected format: "row,col" => boolean
168	    const sparseGrid = new Map<string, boolean>();
169	    sparseGrid.set("-1,-1", false);
170	    sparseGrid.set("-1,0", false);
171	    sparseGrid.set("-1,1", false);
172	    sparseGrid.set("0,-1", false);
173	    sparseGrid.set("0,0", true);
174	    sparseGrid.set("0,1", false);
175	    sparseGrid.set("1,-1", false);
176	    sparseGrid.set("1,0", false);
177	    sparseGrid.set("1,1", false);
178	
179	    const result = nextGenerationSparse(sparseGrid);
180	    // Single live cell with 0 neighbors should die
181	    expect(result.get("0,0")).toBe(false);
182	  });
183	  it.todo("should handle blinker pattern oscillation");
184	  it.todo("should handle block pattern persistence");
185	});
