1	export type Cell = boolean;
2	export type Grid = Cell[][];
3	
4	const SURVIVAL_NEIGHBORS = [2, 3];
5	const REPRODUCTION_NEIGHBORS = 3;
6	const NEIGHBOR_OFFSETS = [
7	  [-1, -1], [-1, 0], [-1, 1],
8	  [0, -1],           [0, 1],
9	  [1, -1],  [1, 0],  [1, 1],
10	] as const;
11	
12	const countNeighbors = (grid: Grid, row: number, col: number): number => {
13	  if (grid.length === 0) {
14	    return 0;
15	  }
16	  const rows = grid.length;
17	  const cols = grid[0].length;
18	  let count = 0;
19	
20	  for (const [dr, dc] of NEIGHBOR_OFFSETS) {
21	    const r = row + dr;
22	    const c = col + dc;
23	    if (r >= 0 && r < rows && c >= 0 && c < cols && grid[r][c]) {
24	      count++;
25	    }
26	  }
27	  return count;
28	};
29	
30	const shouldCellBeAlive = (isAlive: boolean, neighbors: number): boolean =>
31	  (isAlive && SURVIVAL_NEIGHBORS.includes(neighbors)) ||
32	  (!isAlive && neighbors === REPRODUCTION_NEIGHBORS);
33	
34	export const nextGeneration = (grid: Grid): Grid => {
35	  if (grid.length === 0) {
36	    return [];
37	  }
38	
39	  return grid.map((row, rowIdx) =>
40	    row.map((cell, colIdx) => {
41	      const neighbors = countNeighbors(grid, rowIdx, colIdx);
42	      return shouldCellBeAlive(cell, neighbors);
43	    })
44	  );
45	};
46	
47	export const nextGenerationSparse = (
48	  grid: Map<string, boolean>
49	): Map<string, boolean> => {
50	  return new Map();
51	};
52	

